// Example structure of the TOOL_REGISTRY array in Plan My Today
const TOOL_REGISTRY = [
  {
    name: 'list-all-tasks-today',
    description: 'Aggregates and prioritizes all tasks from external sources for today.',
    schema: z.object({ /* input schema */ }),
    handler: async (input, ctx) => {
      // Async handler logic
      const results = await Promise.allSettled([
        fetchGoogleCalendar(),
        fetchLinearIssues(),
        fetchGithubPRs(),
        // ... other sources
      ]);
      return formatMCPResponse(results);
    }
  },
  {
    name: 'update-task-priority',
    description: 'Manually adjust a task priority in the local store.',
    schema: z.object({ taskId: z.string(), newPriority: z.enum(['critical', 'high', 'medium', 'low']) }),
    handler: async (input) => {
      // Update local JSON store
      const tasks = readLocalTasks();
      tasks[input.taskId].priority = input.newPriority;
      writeLocalTasks(tasks);
      return { success: true };
    }
  }
  // ... other tools
];
